#!/usr/bin/env node
/**
 * update-webapp-seo.mjs
 *
 * Reads trending keyword data from gsc_keywords.db and writes two outputs:
 *
 *  1. stage-webapp/src/config/seo-keywords.ts
 *     Auto-generated TypeScript config — top trending keywords per dialect.
 *     Imported by page metadata to populate <meta name="keywords">.
 *     Integration into page.tsx is handled separately by AutoFix Deploy Engineer.
 *
 *  2. seo/latest-keywords.json  (in stage-seo-pipeline repo)
 *     Machine-readable trigger file read by the Paperclip heartbeat agent to
 *     create a Paperclip integration issue for AutoFix Deploy Engineer.
 *
 * Usage:
 *   node scripts/update-webapp-seo.mjs \
 *     --db gsc_keywords.db \
 *     --webapp ../../stage-webapp \
 *     --pipeline-root . \
 *     --limit 10
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'node:fs';
import { resolve, join, dirname } from 'node:path';

// ── Args ──────────────────────────────────────────────────────────────────────
const args = process.argv.slice(2);
function getArg(flag, defaultValue) {
  const idx = args.indexOf(flag);
  return idx !== -1 ? args[idx + 1] : defaultValue;
}

const DB_PATH       = resolve(getArg('--db',            'gsc_keywords.db'));
const WEBAPP        = resolve(getArg('--webapp',        '../../../stage-webapp'));
const PIPELINE_ROOT = resolve(getArg('--pipeline-root', '.'));
const LIMIT         = parseInt(getArg('--limit',        '10'), 10);
const DATE          = new Date().toISOString().split('T')[0];

// ── Load DB with sql.js ───────────────────────────────────────────────────────
async function loadDb(dbPath) {
  const { default: initSqlJs } = await import('sql.js');
  const SQL = await initSqlJs();
  if (!existsSync(dbPath)) throw new Error(`DB not found: ${dbPath}`);
  const buf = readFileSync(dbPath);
  return new SQL.Database(buf);
}

// ── Query top rising keywords per dialect ────────────────────────────────────
function queryDialectKeywords(db, dialect, limit) {
  const result = db.exec(`
    SELECT query, clicks_delta, clicks_delta_pct
    FROM   keyword_trends
    WHERE  dialect   = '${dialect}'
      AND  direction IN ('rising', 'new')
      AND  clicks_delta > 0
    ORDER  BY clicks_delta DESC
    LIMIT  ${limit}
  `);
  if (!result.length || !result[0].values.length) return [];
  return result[0].values.map(row => ({
    query: row[0],
    clicksDelta: row[1],
    clicksDeltaPct: Math.round(row[2]),
  }));
}

// ── Write src/config/seo-keywords.ts ─────────────────────────────────────────
function writeSeoKeywordsConfig(webapp, keywordsByDialect) {
  const outPath = join(webapp, 'src/config/seo-keywords.ts');
  mkdirSync(dirname(outPath), { recursive: true });

  const lines = [
    `// Auto-generated by SEO weekly keyword analysis`,
    `// Last updated: ${DATE}`,
    `// Source: Google Search Console (14-day rolling window)`,
    `// DO NOT EDIT MANUALLY — regenerated weekly by GitHub Actions`,
    `//`,
    `// Integration: this file is imported by src/app/[lang]/[dialect]/page.tsx`,
    `// The generateMetadata function should call getSeoKeywords(dialectObj.enum)`,
    `// and include the result as the 'keywords' field in the returned Metadata object.`,
    `// See Paperclip issue for full integration instructions.`,
    ``,
    `export const SEO_TRENDING_KEYWORDS: Record<string, readonly string[]> = {`,
  ];

  for (const [dialect, kws] of Object.entries(keywordsByDialect)) {
    const quoted = kws.map(k => `    ${JSON.stringify(k.query)}`).join(',\n');
    lines.push(`  ${dialect}: [`);
    if (quoted) lines.push(quoted);
    lines.push(`  ],`);
  }

  lines.push(`} as const;`);
  lines.push(``);
  lines.push(`/**`);
  lines.push(` * Returns the top trending GSC keywords for a given dialect.`);
  lines.push(` * Pass dialectObj.enum (e.g. DialectsEnum.HARYANVI = "haryanvi").`);
  lines.push(` */`);
  lines.push(`export function getSeoKeywords(dialect: string): string[] {`);
  lines.push(`  const key = dialect.toLowerCase();`);
  lines.push(`  return [...(SEO_TRENDING_KEYWORDS[key] ?? [])];`);
  lines.push(`}`);
  lines.push(``);

  writeFileSync(outPath, lines.join('\n'), 'utf8');
  console.log(`✅ Written ${outPath}`);
  return outPath;
}

// ── Write seo/latest-keywords.json (trigger file for Paperclip heartbeat) ────
function writeTriggerFile(pipelineRoot, keywordsByDialect, stats) {
  const dir = join(pipelineRoot, 'seo');
  mkdirSync(dir, { recursive: true });
  const outPath = join(dir, 'latest-keywords.json');

  const payload = {
    generatedAt: new Date().toISOString(),
    date: DATE,
    stats,
    keywords: keywordsByDialect,
    integration: {
      targetRepo: 'vatsanatech/stage-webapp',
      targetFile: 'src/config/seo-keywords.ts',
      pageFile: 'src/app/[lang]/[dialect]/page.tsx',
      instructions: [
        'Import getSeoKeywords from @/config/seo-keywords',
        'In generateMetadata, add: keywords: getSeoKeywords(dialectObj.enum)',
        'seo-keywords.ts is already updated in the weekly PR — only page.tsx needs patching',
      ],
    },
  };

  writeFileSync(outPath, JSON.stringify(payload, null, 2), 'utf8');
  console.log(`✅ Written ${outPath}`);
  return outPath;
}

// ── Main ─────────────────────────────────────────────────────────────────────
async function main() {
  console.log(`\n=== SEO Keyword Webapp Updater ===`);
  console.log(`DB:       ${DB_PATH}`);
  console.log(`Webapp:   ${WEBAPP}`);
  console.log(`Pipeline: ${PIPELINE_ROOT}`);
  console.log(`Date:     ${DATE}`);
  console.log(`Limit:    ${LIMIT} keywords/dialect\n`);

  const db = await loadDb(DB_PATH);

  const DIALECTS = ['haryanvi', 'rajasthani', 'bhojpuri', 'gujarati'];
  const keywordsByDialect = {};
  const stats = {};

  for (const dialect of DIALECTS) {
    const kws = queryDialectKeywords(db, dialect, LIMIT);
    keywordsByDialect[dialect] = kws;
    stats[dialect] = kws.length;
    console.log(`  ${dialect}: ${kws.length} keywords`);
    if (kws.length) {
      console.log(`    top 3: ${kws.slice(0, 3).map(k => k.query).join(', ')}`);
    }
  }

  db.close();

  writeSeoKeywordsConfig(WEBAPP, keywordsByDialect);
  writeTriggerFile(PIPELINE_ROOT, keywordsByDialect, stats);

  console.log('\n✅ Done');
}

main().catch(err => {
  console.error('❌ Error:', err.message);
  process.exit(1);
});
